# Animation Patterns

Common animation patterns and techniques with typestyles


TypeStyles supports CSS animations through the `keyframes` API. This guide covers common animation patterns and best practices.

## Basic animations

### Fade in

```ts
import { keyframes, styles } from 'typestyles';

const fadeIn = keyframes.create('fadeIn', {
  from: { opacity: 0 },
  to: { opacity: 1 },
});

const card = styles.component('card', {
  base: {
    animation: `${fadeIn} 300ms ease`,
  },
});
```

### Slide in

```ts
const slideInRight = keyframes.create('slideInRight', {
  from: {
    opacity: 0,
    transform: 'translateX(20px)',
  },
  to: {
    opacity: 1,
    transform: 'translateX(0)',
  },
});

const slideInLeft = keyframes.create('slideInLeft', {
  from: {
    opacity: 0,
    transform: 'translateX(-20px)',
  },
  to: {
    opacity: 1,
    transform: 'translateX(0)',
  },
});

const slideInUp = keyframes.create('slideInUp', {
  from: {
    opacity: 0,
    transform: 'translateY(20px)',
  },
  to: {
    opacity: 1,
    transform: 'translateY(0)',
  },
});

const slideInDown = keyframes.create('slideInDown', {
  from: {
    opacity: 0,
    transform: 'translateY(-20px)',
  },
  to: {
    opacity: 1,
    transform: 'translateY(0)',
  },
});
```

### Scale animations

```ts
const scaleIn = keyframes.create('scaleIn', {
  from: {
    opacity: 0,
    transform: 'scale(0.9)',
  },
  to: {
    opacity: 1,
    transform: 'scale(1)',
  },
});

const scaleOut = keyframes.create('scaleOut', {
  from: {
    opacity: 1,
    transform: 'scale(1)',
  },
  to: {
    opacity: 0,
    transform: 'scale(0.9)',
  },
});

const popIn = keyframes.create('popIn', {
  '0%': { transform: 'scale(0)' },
  '70%': { transform: 'scale(1.1)' },
  '100%': { transform: 'scale(1)' },
});
```

## Common UI animations

### Loading spinner

```ts
const spin = keyframes.create('spin', {
  from: { transform: 'rotate(0deg)' },
  to: { transform: 'rotate(360deg)' },
});

const spinner = styles.component('spinner', {
  base: {
    display: 'inline-block',
    width: '24px',
    height: '24px',
    border: '3px solid #e5e7eb',
    borderTopColor: '#3b82f6',
    borderRadius: '50%',
    animation: `${spin} 800ms linear infinite`,
  },

  sm: {
    width: '16px',
    height: '16px',
    borderWidth: '2px',
  },

  lg: {
    width: '32px',
    height: '32px',
    borderWidth: '4px',
  },
});
```

### Pulse animation

```ts
const pulse = keyframes.create('pulse', {
  '0%, 100%': { opacity: 1 },
  '50%': { opacity: 0.5 },
});

const skeleton = styles.component('skeleton', {
  base: {
    backgroundColor: '#e5e7eb',
    borderRadius: '4px',
    animation: `${pulse} 2s ease-in-out infinite`,
  },
});
```

### Shake animation (error state)

```ts
const shake = keyframes.create('shake', {
  '0%, 100%': { transform: 'translateX(0)' },
  '10%, 30%, 50%, 70%, 90%': { transform: 'translateX(-4px)' },
  '20%, 40%, 60%, 80%': { transform: 'translateX(4px)' },
});

const input = styles.component('input', {
  base: { ... },
  error: {
    borderColor: '#ef4444',
    animation: `${shake} 500ms ease-in-out`,
  },
});
```

### Bounce animation

```ts
const bounce = keyframes.create('bounce', {
  '0%, 100%': {
    transform: 'translateY(0)',
    animationTimingFunction: 'cubic-bezier(0.8, 0, 1, 1)',
  },
  '50%': {
    transform: 'translateY(-25%)',
    animationTimingFunction: 'cubic-bezier(0, 0, 0.2, 1)',
  },
});

const notification = styles.component('notification', {
  badge: {
    animation: `${bounce} 1s infinite`,
  },
});
```

## Page transitions

### Page fade

```ts
const pageFadeIn = keyframes.create('pageFadeIn', {
  from: { opacity: 0 },
  to: { opacity: 1 },
});

const pageLayout = styles.component('page', {
  container: {
    animation: `${pageFadeIn} 300ms ease`,
  },
});
```

### Staggered list items

```ts
// Individual item animation
const listItemFadeIn = keyframes.create('listItemFadeIn', {
  from: {
    opacity: 0,
    transform: 'translateY(10px)',
  },
  to: {
    opacity: 1,
    transform: 'translateY(0)',
  },
});

// Delay classes for stagger effect
const list = styles.component('list', {
  item: {
    opacity: 0,
    animation: `${listItemFadeIn} 300ms ease forwards`,
  },

  itemDelay1: { animationDelay: '50ms' },
  itemDelay2: { animationDelay: '100ms' },
  itemDelay3: { animationDelay: '150ms' },
  itemDelay4: { animationDelay: '200ms' },
  itemDelay5: { animationDelay: '250ms' },
});

// React usage with index
function List({ items }) {
  return (
    <ul>
      {items.map((item, index) => (
        <li
          key={item.id}
          className={list(
            'item',
            index === 0 && 'itemDelay1',
            index === 1 && 'itemDelay2',
            index === 2 && 'itemDelay3',
            // ... or use a function to calculate delay
          )}
        >
          {item.name}
        </li>
      ))}
    </ul>
  );
}
```

## Micro-interactions

### Button press

```ts
const buttonPress = keyframes.create('buttonPress', {
  '0%': { transform: 'scale(1)' },
  '50%': { transform: 'scale(0.95)' },
  '100%': { transform: 'scale(1)' },
});

const button = styles.component('button', {
  base: {
    transition: 'transform 100ms ease',

    '&:active': {
      transform: 'scale(0.95)',
    },
  },

  // Or with keyframe for more control
  press: {
    animation: `${buttonPress} 150ms ease`,
  },
});
```

### Checkbox check

```ts
const checkmark = keyframes.create('checkmark', {
  '0%': {
    strokeDashoffset: 100,
  },
  '100%': {
    strokeDashoffset: 0,
  },
});

const checkbox = styles.component('checkbox', {
  base: { ... },

  checkmark: {
    strokeDasharray: 100,
    strokeDashoffset: 100,
  },

  checked: {
    '& .checkmark': {
      animation: `${checkmark} 200ms ease forwards`,
    },
  },
});
```

### Hover lift effect

```ts
const card = styles.component('card', {
  base: {
    transition: 'transform 200ms ease, box-shadow 200ms ease',
  },

  interactive: {
    cursor: 'pointer',

    '&:hover': {
      transform: 'translateY(-4px)',
      boxShadow: '0 12px 24px rgba(0, 0, 0, 0.15)',
    },
  },
});
```

## Complex animations

### Modal enter/exit

```ts
const modalBackdropFadeIn = keyframes.create('modalBackdropFadeIn', {
  from: { opacity: 0 },
  to: { opacity: 1 },
});

const modalBackdropFadeOut = keyframes.create('modalBackdropFadeOut', {
  from: { opacity: 1 },
  to: { opacity: 0 },
});

const modalContentSlideIn = keyframes.create('modalContentSlideIn', {
  from: {
    opacity: 0,
    transform: 'scale(0.95) translateY(10px)',
  },
  to: {
    opacity: 1,
    transform: 'scale(1) translateY(0)',
  },
});

const modalContentSlideOut = keyframes.create('modalContentSlideOut', {
  from: {
    opacity: 1,
    transform: 'scale(1) translateY(0)',
  },
  to: {
    opacity: 0,
    transform: 'scale(0.95) translateY(10px)',
  },
});

const modal = styles.component('modal', {
  backdrop: {
    position: 'fixed',
    inset: 0,
    backgroundColor: 'rgba(0, 0, 0, 0.5)',
  },

  backdropEnter: {
    animation: `${modalBackdropFadeIn} 200ms ease`,
  },

  backdropExit: {
    animation: `${modalBackdropFadeOut} 200ms ease forwards`,
  },

  content: {
    backgroundColor: 'white',
    borderRadius: '8px',
    padding: '24px',
  },

  contentEnter: {
    animation: `${modalContentSlideIn} 300ms ease`,
  },

  contentExit: {
    animation: `${modalContentSlideOut} 200ms ease forwards`,
  },
});
```

### Toast notifications

```ts
const toastSlideIn = keyframes.create('toastSlideIn', {
  from: {
    opacity: 0,
    transform: 'translateX(100%)',
  },
  to: {
    opacity: 1,
    transform: 'translateX(0)',
  },
});

const toastSlideOut = keyframes.create('toastSlideOut', {
  from: {
    opacity: 1,
    transform: 'translateX(0)',
  },
  to: {
    opacity: 0,
    transform: 'translateX(100%)',
  },
});

const toastProgress = keyframes.create('toastProgress', {
  from: { transform: 'scaleX(1)' },
  to: { transform: 'scaleX(0)' },
});

const toast = styles.component('toast', {
  base: {
    padding: '16px 20px',
    borderRadius: '8px',
    boxShadow: '0 4px 12px rgba(0, 0, 0, 0.15)',
  },

  enter: {
    animation: `${toastSlideIn} 300ms ease`,
  },

  exit: {
    animation: `${toastSlideOut} 300ms ease forwards`,
  },

  progressBar: {
    height: '3px',
    backgroundColor: 'rgba(255, 255, 255, 0.3)',
    marginTop: '12px',
    transformOrigin: 'left',
    animation: `${toastProgress} 5000ms linear forwards`,
  },

  success: {
    backgroundColor: '#10b981',
    color: 'white',
  },

  error: {
    backgroundColor: '#ef4444',
    color: 'white',
  },

  info: {
    backgroundColor: '#3b82f6',
    color: 'white',
  },
});
```

### Skeleton loading

```ts
const shimmer = keyframes.create('shimmer', {
  '0%': { backgroundPosition: '-200% 0' },
  '100%': { backgroundPosition: '200% 0' },
});

const skeleton = styles.component('skeleton', {
  base: {
    backgroundColor: '#e5e7eb',
    borderRadius: '4px',
  },

  animated: {
    background: 'linear-gradient(90deg, #e5e7eb 25%, #f3f4f6 50%, #e5e7eb 75%)',
    backgroundSize: '200% 100%',
    animation: `${shimmer} 1.5s infinite`,
  },

  text: {
    height: '1em',
    marginBottom: '0.5em',
  },

  textLarge: {
    height: '1.5em',
  },

  circle: {
    borderRadius: '50%',
  },

  avatar: {
    width: '40px',
    height: '40px',
  },

  card: {
    height: '200px',
  },
});
```

## Scroll animations

### Infinite scroll indicator

```ts
const scrollIndicator = keyframes.create('scrollIndicator', {
  '0%, 100%': {
    opacity: 1,
    transform: 'translateY(0)',
  },
  '50%': {
    opacity: 0.5,
    transform: 'translateY(6px)',
  },
});

const scrollCue = styles.component('scroll-cue', {
  base: {
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    gap: '4px',
  },

  arrow: {
    animation: `${scrollIndicator} 1.5s ease-in-out infinite`,
  },

  arrowDelay1: { animationDelay: '0ms' },
  arrowDelay2: { animationDelay: '150ms' },
  arrowDelay3: { animationDelay: '300ms' },
});
```

## Best practices

### Performance

```ts
// ✅ Use transform and opacity for smooth animations
const goodAnimation = keyframes.create('goodAnimation', {
  from: {
    opacity: 0,
    transform: 'translateY(20px)', // GPU accelerated
  },
  to: {
    opacity: 1,
    transform: 'translateY(0)',
  },
});

// ❌ Avoid animating layout properties
const badAnimation = keyframes.create('badAnimation', {
  from: {
    height: 0, // Triggers layout
    marginTop: 0, // Triggers layout
  },
  to: {
    height: '100px',
    marginTop: '20px',
  },
});
```

### Accessibility

```ts
// Respect reduced motion preference
const animated = styles.component('animated', {
  base: {
    '@media (prefers-reduced-motion: reduce)': {
      animation: 'none',
      transition: 'none',
    },
  },
});
```

### Timing functions

```ts
// Standard curves
const ease = 'ease'; // Standard
const easeIn = 'ease-in'; // Accelerate
const easeOut = 'ease-out'; // Decelerate
const easeInOut = 'ease-in-out'; // Both

// Custom cubic-bezier for specific feels
const springy = 'cubic-bezier(0.68, -0.55, 0.265, 1.55)';
const smooth = 'cubic-bezier(0.4, 0, 0.2, 1)';
const enter = 'cubic-bezier(0, 0, 0.2, 1)';
const exit = 'cubic-bezier(0.4, 0, 1, 1)';

// Usage
const button = styles.component('button', {
  base: {
    transition: `transform 200ms ${springy}`,
  },
});
```

### Duration guidelines

| Animation Type    | Duration  | Use Case                    |
| ----------------- | --------- | --------------------------- |
| Micro-interaction | 100-200ms | Button press, hover states  |
| Standard          | 200-300ms | Modals, dropdowns, tooltips |
| Complex           | 300-500ms | Page transitions, reveals   |
| Ambient           | 1-10s     | Loading states, skeletons   |

### Naming conventions

```ts
// Use descriptive names
const fadeIn = keyframes.create('fadeIn', { ... });
const slideUp = keyframes.create('slideUp', { ... });
const modalEnter = keyframes.create('modalEnter', { ... });
const modalExit = keyframes.create('modalExit', { ... });

// Include direction when applicable
const slideInRight = keyframes.create('slideInRight', { ... });
const slideInLeft = keyframes.create('slideInLeft', { ... });
const slideOutUp = keyframes.create('slideOutUp', { ... });
```

## Animation utilities

### Animation delay helper

```ts
function createStaggeredAnimation(
  baseName: string,
  itemCount: number,
  baseDelay: number
): Record<string, string> {
  const delays: Record<string, string> = {};

  for (let i = 0; i < itemCount; i++) {
    delays[`delay${i + 1}`] = `${baseDelay * (i + 1)}ms`;
  }

  return delays;
}

// Usage in React
function StaggeredList({ items }) {
  const delayClass = (index: number) => {
    const delays = ['delay1', 'delay2', 'delay3', 'delay4', 'delay5'];
    return delays[index] || 'delay5';
  };

  return (
    <ul>
      {items.map((item, index) => (
        <li
          key={item.id}
          className={list('item', delayClass(index))}
        >
          {item.name}
        </li>
      ))}
    </ul>
  );
}
```

### Animation presets

```ts
// animations/presets.ts
export const presets = {
  fade: {
    in: 'fadeIn 300ms ease',
    out: 'fadeOut 200ms ease',
  },
  slide: {
    up: 'slideUp 300ms ease',
    down: 'slideDown 300ms ease',
    left: 'slideLeft 300ms ease',
    right: 'slideRight 300ms ease',
  },
  scale: {
    in: 'scaleIn 200ms ease',
    out: 'scaleOut 200ms ease',
  },
  bounce: 'bounce 500ms ease',
  pulse: 'pulse 2s ease-in-out infinite',
  spin: 'spin 1s linear infinite',
  shake: 'shake 500ms ease-in-out',
} as const;

// Usage
const modal = styles.component('modal', {
  enter: {
    animation: presets.fade.in,
  },
});
```

## Summary

1. **Use transform and opacity** - Best performance
2. **Respect reduced motion** - Accessibility first
3. **Keep animations purposeful** - Don't animate just because you can
4. **Use appropriate timing** - Match animation to importance
5. **Consider physics** - Natural motion feels better
6. **Test on real devices** - Performance varies
7. **Name descriptively** - Make intent clear
8. **Reuse animations** - Create a preset library
9. **Document timing** - Help other developers
10. **Test with users** - Get feedback on feel

Source: https://typestyles.dev/docs/animation-patterns

atomic-css.markdown:
# Atomic CSS Utilities

Type-safe atomic CSS utilities with @typestyles/props


The `@typestyles/props` package provides a type-safe way to generate atomic CSS utility classes, similar to Tailwind CSS but with full TypeScript inference and zero runtime overhead.

Runtime APIs such as `styles.class`, `styles.component`, and `styles.hashClass` use a separate naming system; to change those class strings (semantic vs hashed), see [Class naming](/docs/class-naming).

**Compare approaches:** this package (`defineProperties` + `createProps`) powers layout utilities on the docs site ([`docs/src/atoms.ts`](https://github.com/type-styles/typestyles/blob/main/docs/src/atoms.ts)). For hand-written `styles.class` utilities (Tailwind-style), see [examples/typewind](https://github.com/type-styles/typestyles/blob/main/examples/typewind/README.md).

## Installation

```bash
npm install @typestyles/props
```

## Quick Start

```ts
import { defineProperties, createProps } from '@typestyles/props';

// Define your atomic utilities
const atoms = createProps(
  'atom',
  defineProperties({
    properties: {
      display: ['flex', 'block', 'grid', 'none'],
      padding: { 0: '0', 1: '4px', 2: '8px', 3: '16px' },
      gap: { 0: '0', 1: '4px', 2: '8px', 3: '16px' },
    },
  }),
);

// Use them with full type safety
atoms({
  display: 'flex',
  padding: 2,
  gap: 1,
});
// Returns: "atom-display-flex atom-padding-2 atom-gap-1"
```

## Defining Properties

Use `defineProperties()` to define a collection of CSS properties with their allowed values:

### Array-Based Values

For enumerated values like display modes:

```ts
const utilities = defineProperties({
  properties: {
    display: ['flex', 'block', 'grid', 'none', 'inline-flex'],
    flexDirection: ['row', 'column', 'row-reverse', 'column-reverse'],
    alignItems: ['start', 'center', 'end', 'stretch', 'baseline'],
  },
});
```

### Object-Based Values

For scale-based values like spacing or font sizes:

```ts
const utilities = defineProperties({
  properties: {
    padding: {
      0: '0',
      1: '0.25rem',
      2: '0.5rem',
      3: '0.75rem',
      4: '1rem',
      8: '2rem',
    },
    fontSize: {
      xs: '0.75rem',
      sm: '0.875rem',
      base: '1rem',
      lg: '1.125rem',
      xl: '1.25rem',
    },
  },
});
```

## Responsive Conditions

Add breakpoints and other conditional styles:

```ts
const responsive = defineProperties({
  conditions: {
    mobile: { '@media': '(min-width: 640px)' },
    tablet: { '@media': '(min-width: 768px)' },
    desktop: { '@media': '(min-width: 1024px)' },
  },
  properties: {
    display: ['flex', 'block', 'grid'],
    flexDirection: ['row', 'column'],
  },
});

const atoms = createProps('atom', responsive);

// Apply responsive values
atoms({
  display: 'block', // Base value
  flexDirection: { mobile: 'column', desktop: 'row' }, // Responsive
});
// Returns: "atom-display-block atom-flexDirection-mobile-column atom-flexDirection-desktop-row"
```

### Condition Types

**Media Queries:**

```ts
{ mobile: { '@media': '(min-width: 768px)' } }
```

**Container Queries:**

```ts
{ wide: { '@container': '(min-width: 400px)' } }
```

**Feature Queries:**

```ts
{ supportsGrid: { '@supports': '(display: grid)' } }
```

**Custom Selectors:**

```ts
{
  hover: {
    selector: '&:hover';
  }
}
{
  dark: {
    selector: '[data-theme="dark"] &';
  }
}
```

## Shorthands

Define shorthands that expand to multiple properties:

```ts
const spacing = defineProperties({
  properties: {
    paddingTop: { 0: '0', 1: '4px', 2: '8px' },
    paddingRight: { 0: '0', 1: '4px', 2: '8px' },
    paddingBottom: { 0: '0', 1: '4px', 2: '8px' },
    paddingLeft: { 0: '0', 1: '4px', 2: '8px' },
  },
  shorthands: {
    padding: ['paddingTop', 'paddingRight', 'paddingBottom', 'paddingLeft'],
    paddingX: ['paddingLeft', 'paddingRight'],
    paddingY: ['paddingTop', 'paddingBottom'],
  },
});

const atoms = createProps('atom', spacing);

atoms({ padding: 2 });
// Expands to: paddingTop, paddingRight, paddingBottom, paddingLeft all set to 2
// Returns: "atom-paddingTop-2 atom-paddingRight-2 atom-paddingBottom-2 atom-paddingLeft-2"

atoms({ paddingX: 1, paddingY: 2 });
// Returns: "atom-paddingLeft-1 atom-paddingRight-1 atom-paddingTop-2 atom-paddingBottom-2"
```

## Combining Property Collections

Merge multiple property collections into one props function:

```ts
const layout = defineProperties({
  properties: {
    display: ['flex', 'block', 'grid'],
    position: ['relative', 'absolute', 'fixed', 'sticky'],
  },
});

const spacing = defineProperties({
  properties: {
    padding: { 0: '0', 1: '4px', 2: '8px' },
    margin: { 0: '0', 1: '4px', 2: '8px', auto: 'auto' },
  },
});

const colors = defineProperties({
  properties: {
    color: { primary: '#0066ff', secondary: '#6b7280' },
    backgroundColor: { white: '#ffffff', gray: '#f3f4f6' },
  },
});

// Combine all collections
const atoms = createProps('atom', layout, spacing, colors);

// Use properties from any collection
atoms({
  display: 'flex',
  padding: 2,
  color: 'primary',
});
```

## Default Conditions

Set a default condition for all property values:

```ts
const mobileFirst = defineProperties({
  conditions: {
    tablet: { '@media': '(min-width: 768px)' },
    desktop: { '@media': '(min-width: 1024px)' },
  },
  defaultCondition: false, // No condition by default (mobile-first)
  properties: {
    fontSize: { sm: '14px', base: '16px', lg: '18px' },
  },
});

const desktopFirst = defineProperties({
  conditions: {
    mobile: { '@media': '(max-width: 768px)' },
  },
  defaultCondition: 'mobile', // All values get mobile condition by default
  properties: {
    fontSize: { sm: '14px', base: '16px', lg: '18px' },
  },
});
```

## SSR Support

CSS is automatically injected and available for SSR:

```ts
import { getRegisteredCss } from 'typestyles';

// Define and create your atoms
const atoms = createProps(
  'atom',
  defineProperties({
    /* ... */
  }),
);

// CSS is automatically registered
const css = getRegisteredCss();
// Contains all atomic utility classes
```

## Composing with Component Styles

Combine atomic utilities with component-specific styles using `styles.compose()`:

```ts
import { styles } from 'typestyles';
import { createProps, defineProperties } from '@typestyles/props';

const atoms = createProps(
  'atom',
  defineProperties({
    properties: {
      display: ['flex', 'grid'],
      gap: { 0: '0', 1: '4px', 2: '8px' },
      padding: { 0: '0', 1: '4px', 2: '8px', 3: '16px' },
    },
  }),
);

const card = styles.component('card', {
  base: {
    borderRadius: '8px',
    border: '1px solid #e5e5e5',
    background: 'white',
  },
});

// Compose together
const flexCard = styles.compose(card, atoms({ display: 'flex', gap: 2, padding: 3 }));

flexCard();
// "card-base atom-display-flex atom-gap-2 atom-padding-3"
```

## Real-World Example

Building a complete design system:

```ts
import { defineProperties, createProps } from '@typestyles/props';

// Define responsive breakpoints and utilities
const atoms = createProps(
  'ds',
  defineProperties({
    conditions: {
      sm: { '@media': '(min-width: 640px)' },
      md: { '@media': '(min-width: 768px)' },
      lg: { '@media': '(min-width: 1024px)' },
      xl: { '@media': '(min-width: 1280px)' },
      dark: { selector: '[data-theme="dark"] &' },
      hover: { selector: '&:hover' },
    },
    properties: {
      // Layout
      display: ['none', 'flex', 'block', 'grid', 'inline-flex'],
      flexDirection: ['row', 'column'],
      alignItems: ['start', 'center', 'end', 'stretch'],
      justifyContent: ['start', 'center', 'end', 'between', 'around'],

      // Spacing
      gap: { 0: '0', 1: '0.25rem', 2: '0.5rem', 3: '0.75rem', 4: '1rem' },
      padding: { 0: '0', 1: '0.25rem', 2: '0.5rem', 4: '1rem', 8: '2rem' },
      margin: { 0: '0', auto: 'auto', 1: '0.25rem', 2: '0.5rem' },

      // Typography
      fontSize: { xs: '0.75rem', sm: '0.875rem', base: '1rem', lg: '1.125rem' },
      fontWeight: { normal: '400', medium: '500', semibold: '600', bold: '700' },

      // Colors
      color: { primary: '#3b82f6', secondary: '#64748b', muted: '#94a3b8' },
      backgroundColor: { white: '#fff', gray: '#f1f5f9', transparent: 'transparent' },
    },
    shorthands: {
      p: ['padding'],
      px: ['paddingLeft', 'paddingRight'],
      py: ['paddingTop', 'paddingBottom'],
      m: ['margin'],
    },
  })
);

// Use in components
export function Button() {
  return (
    <button
      className={atoms({
        display: 'inline-flex',
        alignItems: 'center',
        gap: 2,
        px: 4,
        py: 2,
        fontSize: { sm: 'sm', md: 'base' },
        fontWeight: 'semibold',
        color: 'white',
        backgroundColor: { _: 'primary', hover: 'secondary', dark: 'gray' },
      })}
    >
      Click me
    </button>
  );
}
```

## Class Naming

Classes follow a predictable pattern:

```
{namespace}-{property}-{value}
{namespace}-{property}-{condition}-{value}
```

Examples:

- `atom-display-flex`
- `atom-display-mobile-block`
- `atom-padding-2`
- `atom-padding-desktop-4`

## TypeScript

Full type inference and autocomplete for:

- Property names
- Property values
- Condition names
- Shorthand names

```ts
const atoms = createProps(
  'atom',
  defineProperties({
    properties: {
      display: ['flex', 'block'],
    },
  }),
);

atoms({ display: 'flex' }); // ✅
atoms({ display: 'grid' }); // ❌ Type error: 'grid' not in ['flex', 'block']
atoms({ fontSize: '16px' }); // ❌ Type error: 'fontSize' not defined
```

## Inspecting Properties

Check which properties are available:

```ts
const atoms = createProps(
  'atom',
  defineProperties({
    properties: { display: ['flex', 'block'] },
    shorthands: { d: ['display'] },
  }),
);

atoms.properties.has('display'); // true
atoms.properties.has('d'); // true (shorthand)
atoms.properties.has('fontSize'); // false
```

## Performance

- **Zero runtime overhead** - All CSS is pre-generated at module load time
- **Automatic deduplication** - Classes are only generated once
- **Small bundle size** - Only the props function and a lookup map are included
- **Fast runtime** - Just string concatenation, no CSS generation at runtime

Source: https://typestyles.dev/docs/atomic-css

best-practices.markdown:
# Best Practices

Tips for organizing and maintaining typestyles in your project


These guidelines will help you write maintainable, scalable code with typestyles.

## Naming conventions

### Namespaces

Use kebab-case for namespaces. The namespace should describe the component or pattern:

```ts
// Good - descriptive and consistent
const button = styles.component('button', { ... });
const card = styles.component('card', { ... });
const navigationMenu = styles.component('navigation-menu', { ... });

// Avoid - generic or single-letter names
const b = styles.component('b', { ... });
const x = styles.component('x', { ... });
const component = styles.component('component', { ... });
```

### Variants

Use camelCase for variant dimension names. Be descriptive about the style purpose, not just the visual appearance:

```ts
const button = styles.component('button', {
  base: { ... },
  variants: {
    intent: {
      primary: { ... },     // The main action
      secondary: { ... },   // Alternative action
      danger: { ... },      // Destructive action
      ghost: { ... },       // Subtle action
    },
    size: {
      small: { ... },
      medium: { ... },
      large: { ... },
    },
  },
  defaultVariants: {
    intent: 'primary',
    size: 'medium',
  },
});

// Avoid - describes appearance only
// blue: { ... }, big: { ... }, rounded: { ... }
```

For flat configs, variant names should still be descriptive:

```ts
const card = styles.component('card', {
  base: { ... },
  elevated: { ... },
  interactive: { ... },
  disabled: { ... },
});
```

### Tokens

Group tokens by category. Use consistent naming within groups:

```ts
// Good - clear categories and consistent naming
export const color = tokens.create('color', {
  // Semantic colors
  primary: '#0066ff',
  secondary: '#6b7280',
  success: '#10b981',
  warning: '#f59e0b',
  danger: '#ef4444',

  // Neutral scale
  gray50: '#f9fafb',
  gray100: '#f3f4f6',
  gray200: '#e5e7eb',
  // ...etc

  // Text colors
  text: '#111827',
  textMuted: '#6b7280',
  textInverse: '#ffffff',

  // Surface colors
  surface: '#ffffff',
  surfaceRaised: '#f9fafb',
  surfaceSunken: '#f3f4f6',
});

export const space = tokens.create('space', {
  // Scale-based
  0: '0',
  1: '4px',
  2: '8px',
  3: '12px',
  4: '16px',
  5: '20px',
  6: '24px',
  8: '32px',
  10: '40px',
  12: '48px',
  16: '64px',
  20: '80px',
  24: '96px',

  // Semantic aliases (optional)
  xs: '4px',
  sm: '8px',
  md: '16px',
  lg: '24px',
  xl: '32px',
});
```

## File organization

### Monorepo/Package structure

```
src/
  tokens/
    index.ts          # Re-exports all tokens
    colors.ts         # Color definitions
    spacing.ts        # Spacing scale
    typography.ts     # Font sizes, line heights
    radii.ts          # Border radius
    shadows.ts        # Box shadows
  components/
    Button/
      index.ts      # Component export
      Button.tsx    # Component implementation
      Button.styles.ts  # Style definitions
    Card/
      index.ts
      Card.tsx
      Card.styles.ts
    ...
  layouts/
    Layout.styles.ts
    ...
  utils/
    styles.ts         # Shared utility styles
```

### Token files

Keep tokens in dedicated files, grouped by category:

```ts
// tokens/colors.ts
import { tokens } from 'typestyles';

export const color = tokens.create('color', {
  // Brand colors
  brand50: '#eff6ff',
  brand100: '#dbeafe',
  brand500: '#3b82f6',
  brand600: '#2563eb',
  brand700: '#1d4ed8',

  // Neutral scale
  gray50: '#f9fafb',
  gray100: '#f3f4f6',
  // ... etc
});

// tokens/index.ts
export { color } from './colors';
export { space } from './spacing';
export { font } from './typography';
```

### Component style files

Keep styles co-located with components or in a separate `.styles.ts` file:

**Option 1: Same file (for simple components)**

```tsx
// Button.tsx
import { styles } from 'typestyles';
import { color, space } from '../tokens';

const button = styles.component('button', {
  base: { ... },
  variants: {
    intent: { primary: { ... }, secondary: { ... } },
  },
  defaultVariants: { intent: 'primary' },
});

export function Button({ variant = 'primary', children }) {
  return <button className={button({ intent: variant })}>{children}</button>;
}
```

**Option 2: Separate file (for complex components)**

```ts
// Button.styles.ts
import { styles } from 'typestyles';
import { color, space } from '../tokens';

export const button = styles.component('button', {
  base: { ... },
  variants: {
    intent: { primary: { ... }, secondary: { ... } },
    size: { small: { ... }, medium: { ... }, large: { ... } },
  },
  defaultVariants: { intent: 'primary', size: 'medium' },
});

// Button.tsx
import { button } from './Button.styles';

export function Button({ variant = 'primary', size = 'medium', children }) {
  return (
    <button className={button({ intent: variant, size })}>
      {children}
    </button>
  );
}
```

## Token architecture

### Semantic vs. literal tokens

Use literal tokens for the design system foundation, semantic tokens for application use:

```ts
// tokens/primitives.ts
// Raw values from your design system
export const primitives = {
  colors: {
    blue500: '#0066ff',
    blue600: '#0052cc',
    gray500: '#6b7280',
    red500: '#ef4444',
  },
  space: {
    1: '4px',
    2: '8px',
    3: '16px',
    4: '24px',
  },
};

// tokens/semantic.ts
// Semantic meanings mapped to primitives
export const color = tokens.create('color', {
  primary: primitives.colors.blue500,
  primaryHover: primitives.colors.blue600,
  secondary: primitives.colors.gray500,
  danger: primitives.colors.red500,
  // ... etc
});

export const space = tokens.create('space', primitives.space);
```

### Component-specific tokens

For complex components, you can scope tokens to just that component:

```ts
// components/Calendar/Calendar.tokens.ts
import { tokens } from 'typestyles';

export const calendar = tokens.create('calendar', {
  daySize: '40px',
  headerHeight: '48px',
  gridGap: '4px',
});

// Usage in Calendar.styles.ts
import { calendar } from './Calendar.tokens';

const calendarStyles = styles.component('calendar', {
  base: {
    width: calendar.daySize,
    height: calendar.daySize,
  },
});
```

### Token composition

Reference other tokens when defining new ones:

```ts
const space = tokens.create('space', {
  1: '4px',
  2: '8px',
  3: '16px',
  4: '24px',
  5: '32px',
});

const size = tokens.create('size', {
  // Reference space tokens for consistency
  sm: space[1], // 4px
  md: space[2], // 8px
  lg: space[3], // 16px
  icon: space[4], // 24px
});
```

## Component patterns

### Compound components

For related components (like Form + Input + Label), use consistent namespacing:

```ts
const form = styles.component('form', {
  base: { ... },
});

const input = styles.component('input', {
  base: { ... },
  variants: {
    state: {
      error: { borderColor: '#ef4444' },
      success: { borderColor: '#10b981' },
    },
  },
});

const label = styles.component('label', {
  base: { ... },
  variants: {
    required: {
      true: { '&::after': { content: '"*"', color: '#ef4444' } },
    },
  },
});

// Usage
<form className={form()}>
  <div>
    <label className={label({ required: true })}>Name</label>
    <input className={input({ state: error ? 'error' : undefined })} />
  </div>
</form>
```

### Variant composition

Use dimensioned variants for structured component APIs:

```ts
const button = styles.component('button', {
  base: {
    display: 'inline-flex',
    alignItems: 'center',
    justifyContent: 'center',
    cursor: 'pointer',
    border: 'none',
    fontWeight: 500,
    transition: 'all 150ms ease',
  },
  variants: {
    intent: {
      primary: { backgroundColor: color.primary, color: '#fff' },
      secondary: { backgroundColor: color.secondary, color: '#fff' },
      ghost: { backgroundColor: 'transparent' },
    },
    size: {
      small: { padding: '4px 8px', fontSize: '12px' },
      medium: { padding: '8px 16px', fontSize: '14px' },
      large: { padding: '12px 24px', fontSize: '16px' },
    },
  },
  defaultVariants: {
    intent: 'primary',
    size: 'medium',
  },
});

// Usage
button(); // Primary medium button
button({ intent: 'ghost', size: 'small' }); // Small ghost button
```

### Layout components

Use layout components with flexible spacing:

```ts
const stack = styles.component('stack', {
  base: {
    display: 'flex',
    flexDirection: 'column',
  },
  variants: {
    gap: {
      1: { gap: space[1] },
      2: { gap: space[2] },
      3: { gap: space[3] },
      4: { gap: space[4] },
    },
  },
  defaultVariants: { gap: 2 },
});

const row = styles.component('row', {
  base: {
    display: 'flex',
    flexDirection: 'row',
    alignItems: 'center',
  },
  variants: {
    gap: {
      1: { gap: space[1] },
      2: { gap: space[2] },
    },
  },
});
```

## State management

### Boolean variants

For simple on/off states, use boolean variants or flat configs:

```ts
const card = styles.component('card', {
  base: { ... },
  elevated: {
    boxShadow: '0 4px 6px rgba(0,0,0,0.1)',
  },
  interactive: {
    cursor: 'pointer',
    '&:hover': {
      boxShadow: '0 8px 12px rgba(0,0,0,0.15)',
    },
  },
});

// Destructure and use cx() for conditional application:
import { cx } from 'typestyles';

const { base, elevated, interactive } = card;
cx(base, isElevated && elevated, isInteractive && interactive);
```

### Complex state

For more complex state combinations, use dimensioned variants:

```ts
const button = styles.component('button', {
  base: { ... },
  variants: {
    intent: { primary: { ... }, secondary: { ... }, ghost: { ... } },
    size: { small: { ... }, medium: { ... }, large: { ... } },
    disabled: { true: { opacity: 0.5, cursor: 'not-allowed' } },
    loading: { true: { cursor: 'wait' } },
  },
  defaultVariants: { intent: 'primary', size: 'medium' },
});

function getButtonClasses({ variant, size, isDisabled, isLoading }: ButtonProps) {
  return button({
    intent: variant,
    size,
    disabled: isDisabled || undefined,
    loading: isLoading || undefined,
  });
}
```

## Theming patterns

### Dark mode with createTheme

```ts
// tokens/index.ts
export const color = tokens.create('color', {
  text: '#111827',
  textMuted: '#6b7280',
  surface: '#ffffff',
  surfaceRaised: '#f9fafb',
});

export const darkTheme = tokens.createTheme('dark', {
  base: {
    color: {
      text: '#e0e0e0',
      textMuted: '#9ca3af',
      surface: '#1a1a2e',
      surfaceRaised: '#25253e',
    },
  },
});

// Apply theme to document body or specific container
document.body.classList.add(darkTheme.className);
```

### Multiple themes

```ts
const brandLight = tokens.createTheme('brand-light', {
  base: {
    /* … */
  },
});
const brandDark = tokens.createTheme('brand-dark', {
  base: {
    /* … */
  },
});
const highContrast = tokens.createTheme('high-contrast', {
  base: {
    /* … */
  },
});
```

## Code style

### Consistent formatting

```ts
// Good - consistent structure
const card = styles.component('card', {
  base: {
    padding: space[4],
    borderRadius: '8px',
    backgroundColor: color.surface,
  },
  elevated: {
    boxShadow: shadow.md,
  },
  interactive: {
    cursor: 'pointer',
    transition: 'box-shadow 200ms ease',
    '&:hover': {
      boxShadow: shadow.lg,
    },
  },
});

// Avoid - inconsistent formatting
const card = styles.component('card', {
  base: { padding: space[4], borderRadius: '8px', backgroundColor: color.surface },
  elevated: { boxShadow: shadow.md },
});
```

### Import organization

```ts
// 1. External imports
import React from 'react';
import { styles, tokens, cx } from 'typestyles';

// 2. Internal absolute imports
import { color, space } from '@/tokens';
import { Button } from '@/components';

// 3. Internal relative imports
import { card } from './Card.styles';
import { useCardState } from './useCardState';
```

## Performance tips

1. **Define styles at module level** - Never create styles inside components
2. **Reuse token references** - Define once, import many times
3. **Minimize variants** - Don't create a variant for every possible state
4. **Use [`createVar()` for dynamic values**](/docs/dynamic-styles) — Keep styles static; set per-instance values via CSS custom properties
5. **Lazy load component styles** - Use dynamic imports for code splitting

## Scope isolation

### Why scopeId matters

In semantic mode (the default), `styles.component('button', …)` produces class names like `button-base`. If two packages — or two files in the same app — both register a `'button'` namespace without a `scopeId`, their CSS rules silently overwrite each other. TypeStyles warns about this in development, but the fix is simple: always set a `scopeId`.

### For applications

Use `createTypeStyles` with a `scopeId` at the root of your styles:

```ts
// src/styles.ts
import { createTypeStyles } from 'typestyles';

export const { styles, tokens } = createTypeStyles({
  scopeId: 'my-app',
});
```

Class names become `my-app-button-base` — unique across your dependency tree.

### For published packages

Published packages **must** use a `scopeId` to avoid colliding with consumer code or other packages. Use the package name and `hashed` mode:

```ts
import { createTypeStyles } from 'typestyles';

export const { styles, tokens } = createTypeStyles({
  scopeId: '@acme/ui',
  mode: 'hashed',
});
```

See the full [Publishing Packages](/docs/publishing-packages) guide for ESLint enforcement, token scoping, and a complete library setup example.

### Per-file isolation (CSS Modules style)

For maximum isolation without choosing a global scope, use `fileScopeId`:

```ts
import { createStyles, fileScopeId } from 'typestyles';

const styles = createStyles({ scopeId: fileScopeId(import.meta) });
```

Each file gets a unique hash-based scope, similar to CSS Modules.

## Common mistakes to avoid

### Creating styles inside components

```tsx
// Bad - creates new styles on every render
function Button({ children }) {
  const button = styles.component('button', { base: { ... } }); // Don't do this
  return <button className={button()}>{children}</button>;
}

// Good - define at module level
const button = styles.component('button', { base: { ... } });

function Button({ children }) {
  return <button className={button()}>{children}</button>;
}
```

### Dynamic style values

```tsx
import { styles, createVar, assignVars } from 'typestyles';

// Bad - creates styles for every possible value
const button = styles.component('button', {
  base: { width: props.width }, // Don't do this
});

// Good - wire dynamic values through CSS custom properties
const widthVar = createVar('buttonWidth');

const button = styles.component('button', {
  base: { display: 'inline-block', width: widthVar },
});

function Button({ width, children }) {
  return (
    <button className={button()} style={assignVars({ [widthVar]: width })}>
      {children}
    </button>
  );
}
```

### Duplicate namespaces

```ts
// File A
const button = styles.component('button', { ... });

// File B
const button = styles.component('button', { ... }); // Collision!

// Fix 1 - use descriptive names
const iconButton = styles.component('icon-button', { ... });
const textButton = styles.component('text-button', { ... });

// Fix 2 (recommended) - use scopeId to isolate
const { styles } = createTypeStyles({ scopeId: 'my-app' });
const button = styles.component('button', { ... }); // "my-app-button-base"
```

## Summary

- Always set a `scopeId` via `createTypeStyles` or `createStyles` — especially in published packages
- Use descriptive, consistent naming for namespaces and variants
- Organize tokens by category in dedicated files
- Define styles at module level, never in components
- Use semantic tokens for application code
- Keep variants focused on style purpose, not appearance
- Use [`createVar()` + `assignVars()`](/docs/dynamic-styles) for per-instance dynamic values
- Use `cx()` from typestyles for conditional class joining
- Use a bundler plugin for [zero-runtime production builds](/docs/zero-runtime)

Source: https://typestyles.dev/docs/best-practices

cascade-layers.markdown:
# Cascade layers (@layer)

Opt-in CSS cascade layers for predictable specificity against global CSS


By default, TypeStyles emits **flat** rules (no `@layer`), matching legacy behavior and keeping the API surface small.

When you opt in with a **`layers`** tuple on `createStyles`, `createTokens`, or the unified **`createTypeStyles`** factory, TypeStyles:

1. Registers a single **`@layer a, b, c;`** preamble (once per distinct stack) so order is deterministic.
2. Wraps each emitted rule block in **`@layer <name> { … }`** for the `layer` you pass on each style call.
3. When **`createTokens({ layers, tokenLayer })`** is used, `:root` custom properties and **theme** rules go into `tokenLayer` so utilities and components can override tokens predictably.

## `createTypeStyles` (recommended for design systems)

One config object gives you matching **`scopeId`**, **`layers`**, and **`tokenLayer`** for both class CSS and token/theme CSS:

```ts
import { createTypeStyles } from 'typestyles';

const { styles, tokens } = createTypeStyles({
  scopeId: 'ds',
  mode: 'semantic',
  layers: ['reset', 'tokens', 'components', 'utilities'] as const,
  tokenLayer: 'tokens',
});

const reset = styles.class('reset', { margin: 0, padding: 0 }, { layer: 'reset' });

const button = styles.component(
  'button',
  {
    base: { padding: '8px 16px' },
    variants: {
      intent: { primary: { backgroundColor: '#0066ff' } },
    },
    defaultVariants: { intent: 'primary' },
  },
  { layer: 'components' },
);

tokens.create('color', { primary: '#0066ff' });
```

Conceptual output:

```css
@layer reset, tokens, components, utilities;
@layer tokens {
  :root {
    /* --ds-color-* */
  }
}
@layer reset {
  .reset {
    margin: 0;
    padding: 0;
  }
}
@layer components {
  .button-base {
    padding: 8px 16px;
  }
}
```

## `createStyles` only

Pass **`layers`** as a `const` tuple (or as `{ order, prependFrameworkLayers? }`). Every **`styles.class`**, **`styles.hashClass`**, and **`styles.component`** call must include **`{ layer: '…' }`**. Layer names must appear in the tuple (not in `prependFrameworkLayers`, which only affects ordering against external frameworks).

```ts
const styles = createStyles({
  layers: { order: ['components'], prependFrameworkLayers: ['bootstrap'] },
});

styles.class('card', { padding: '1rem' }, { layer: 'components' });
```

## `createTokens` with layers

When **`layers`** is set, **`tokenLayer`** is **required**. Token and theme CSS is wrapped in that layer.

```ts
const tokens = createTokens({
  scopeId: 'app',
  layers: ['tokens', 'components'] as const,
  tokenLayer: 'tokens',
});
```

## Default (no layers)

Omit **`layers`** everywhere: no `@layer` in output, and there is no `layer` option on style APIs.

## Notes

- **Multiple instances:** Each factory that passes **`layers`** owns its own stack; preamble keys include **`scopeId`** and full order so different design systems on one page stay distinct.
- **Build / SSR:** Preamble rules are inserted at the **front** of the virtual sheet so `getRegisteredCss()` and extraction see ordering before wrapped blocks.
- **jsdom:** Older parsers may log warnings for `@layer`; real browsers support cascade layers.

See also [Class naming](/docs/class-naming).

Source: https://typestyles.dev/docs/cascade-layers

component-library.markdown:
# Component Library Setup

Building a reusable component library with typestyles


This guide shows you how to set up a reusable component library using typestyles, suitable for publishing to npm.

**Reference implementation:** [examples/react-design-system](https://github.com/type-styles/typestyles/blob/main/examples/react-design-system/README.md) (React Aria wrappers + shared tokens). Consumed by [examples/vite-app](https://github.com/type-styles/typestyles/blob/main/examples/vite-app/README.md) and [examples/next-app](https://github.com/type-styles/typestyles/blob/main/examples/next-app/README.md).

## Project structure

```
my-ui-library/
├── src/
│   ├── tokens/
│   │   ├── index.ts          # Token exports
│   │   ├── colors.ts         # Color definitions
│   │   ├── spacing.ts        # Spacing scale
│   │   └── typography.ts     # Font tokens
│   ├── components/
│   │   ├── Button/
│   │   │   ├── Button.tsx
│   │   │   ├── Button.styles.ts
│   │   │   └── index.ts
│   │   ├── Card/
│   │   │   ├── Card.tsx
│   │   │   ├── Card.styles.ts
│   │   │   └── index.ts
│   │   ├── Input/
│   │   │   └── ...
│   │   └── index.ts          # Component exports
│   ├── utils/
│   │   └── style-utils.ts    # Shared style utilities
│   ├── index.ts              # Main library export
│   └── styles.css            # Optional global CSS
├── package.json
├── tsconfig.json
├── vite.config.ts
└── README.md
```

## Package configuration

### package.json

```json
{
  "name": "@myorg/ui-library",
  "version": "1.0.0",
  "description": "A React component library built with typestyles",
  "type": "module",
  "main": "./dist/index.js",
  "module": "./dist/index.js",
  "types": "./dist/index.d.ts",
  "exports": {
    ".": {
      "import": "./dist/index.js",
      "types": "./dist/index.d.ts"
    },
    "./tokens": {
      "import": "./dist/tokens/index.js",
      "types": "./dist/tokens/index.d.ts"
    },
    "./styles.css": "./dist/styles.css"
  },
  "files": ["dist"],
  "scripts": {
    "build": "tsc && vite build",
    "dev": "vite",
    "test": "vitest",
    "typecheck": "tsc --noEmit"
  },
  "peerDependencies": {
    "react": "^18.0.0",
    "react-dom": "^18.0.0",
    "typestyles": "^1.0.0"
  },
  "devDependencies": {
    "@types/react": "^18.0.0",
    "typestyles": "^1.0.0",
    "typescript": "^5.0.0",
    "vite": "^5.0.0"
  }
}
```

Note: `typestyles` should be a peer dependency so consuming apps can control the version.

## Scope isolation

Published packages **must** use a `scopeId` to prevent class name collisions with consumer code or other libraries. Without one, `styles.component('button', …)` produces `button-base` in both your library and the consuming app — their CSS rules silently overwrite each other.

```ts
// src/styles.ts
import { createTypeStyles } from 'typestyles';

export const { styles, tokens } = createTypeStyles({
  scopeId: '@myorg/ui-library',
});
```

Now all class names are prefixed (`myorg-ui-library-button-base`) and all token custom properties are namespaced (`--myorg-ui-library-color-primary`). See [Best Practices — Scope isolation](/docs/best-practices#scope-isolation) for more options.

## Token system

### Colors

```ts
// src/tokens/colors.ts
import { tokens } from './styles'; // use the scoped instance

export const colors = tokens.create('color', {
  // Brand
  brand50: '#eff6ff',
  brand100: '#dbeafe',
  brand200: '#bfdbfe',
  brand300: '#93c5fd',
  brand400: '#60a5fa',
  brand500: '#3b82f6',
  brand600: '#2563eb',
  brand700: '#1d4ed8',
  brand800: '#1e40af',
  brand900: '#1e3a8a',

  // Gray scale
  gray50: '#f9fafb',
  gray100: '#f3f4f6',
  gray200: '#e5e7eb',
  gray300: '#d1d5db',
  gray400: '#9ca3af',
  gray500: '#6b7280',
  gray600: '#4b5563',
  gray700: '#374151',
  gray800: '#1f2937',
  gray900: '#111827',

  // Semantic
  success: '#10b981',
  warning: '#f59e0b',
  danger: '#ef4444',
  info: '#3b82f6',
});

// Semantic aliases
export const semanticColors = tokens.create('semantic-color', {
  primary: colors.brand500,
  primaryHover: colors.brand600,
  secondary: colors.gray500,
  secondaryHover: colors.gray600,
  text: colors.gray900,
  textMuted: colors.gray500,
  background: colors.gray50,
  surface: '#ffffff',
  surfaceRaised: colors.gray100,
  border: colors.gray200,
});
```

### Spacing

```ts
// src/tokens/spacing.ts
import { tokens } from 'typestyles';

export const spacing = tokens.create('space', {
  0: '0',
  1: '4px',
  2: '8px',
  3: '12px',
  4: '16px',
  5: '20px',
  6: '24px',
  8: '32px',
  10: '40px',
  12: '48px',
  16: '64px',
  20: '80px',
  24: '96px',

  // Semantic aliases
  xs: '4px',
  sm: '8px',
  md: '16px',
  lg: '24px',
  xl: '32px',
  '2xl': '48px',
  '3xl': '64px',
});
```

### Typography

```ts
// src/tokens/typography.ts
import { tokens } from 'typestyles';

export const fontSize = tokens.create('font-size', {
  xs: '0.75rem', // 12px
  sm: '0.875rem', // 14px
  base: '1rem', // 16px
  lg: '1.125rem', // 18px
  xl: '1.25rem', // 20px
  '2xl': '1.5rem', // 24px
  '3xl': '1.875rem', // 30px
  '4xl': '2.25rem', // 36px
});

export const fontWeight = tokens.create('font-weight', {
  normal: '400',
  medium: '500',
  semibold: '600',
  bold: '700',
});

export const lineHeight = tokens.create('line-height', {
  none: '1',
  tight: '1.25',
  snug: '1.375',
  normal: '1.5',
  relaxed: '1.625',
  loose: '2',
});
```

### Token exports

```ts
// src/tokens/index.ts
export { colors, semanticColors } from './colors';
export { spacing } from './spacing';
export { fontSize, fontWeight, lineHeight } from './typography';
```

## Component implementation

### Button component

```ts
// src/components/Button/Button.styles.ts
import { styles } from 'typestyles';
import { semanticColors, spacing, fontSize, fontWeight } from '../../tokens';

export const button = styles.component('button', {
  base: {
    display: 'inline-flex',
    alignItems: 'center',
    justifyContent: 'center',
    gap: spacing[2],
    borderRadius: '6px',
    lineHeight: '1.5',
    cursor: 'pointer',
    border: 'none',
    transition: 'all 150ms ease',

    '&:disabled': {
      opacity: 0.5,
      cursor: 'not-allowed',
    },

    '&:focus': {
      outline: 'none',
      boxShadow: `0 0 0 3px ${semanticColors.primary}33`,
    },
  },
  variants: {
    intent: {
      primary: {
        backgroundColor: semanticColors.primary,
        color: '#ffffff',
        '&:hover:not(:disabled)': {
          backgroundColor: semanticColors.primaryHover,
        },
      },
      secondary: {
        backgroundColor: semanticColors.secondary,
        color: '#ffffff',
        '&:hover:not(:disabled)': {
          backgroundColor: semanticColors.secondaryHover,
        },
      },
      outline: {
        backgroundColor: 'transparent',
        border: `1px solid ${semanticColors.border}`,
        color: semanticColors.text,
        '&:hover:not(:disabled)': {
          backgroundColor: semanticColors.surfaceRaised,
        },
      },
      ghost: {
        backgroundColor: 'transparent',
        color: semanticColors.text,
        '&:hover:not(:disabled)': {
          backgroundColor: semanticColors.surfaceRaised,
        },
      },
    },
    size: {
      sm: {
        padding: `${spacing[1]} ${spacing[3]}`,
        fontSize: fontSize.sm,
        fontWeight: fontWeight.medium,
      },
      md: {
        padding: `${spacing[2]} ${spacing[4]}`,
        fontSize: fontSize.base,
        fontWeight: fontWeight.medium,
      },
      lg: {
        padding: `${spacing[3]} ${spacing[6]}`,
        fontSize: fontSize.lg,
        fontWeight: fontWeight.medium,
      },
    },
    width: {
      auto: {},
      full: { width: '100%' },
    },
  },
  defaultVariants: {
    intent: 'primary',
    size: 'md',
    width: 'auto',
  },
});
```

```tsx
// src/components/Button/Button.tsx
import { cx } from 'typestyles';
import { forwardRef, type ButtonHTMLAttributes, type ReactNode } from 'react';
import { button } from './Button.styles';

export interface ButtonProps extends ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  fullWidth?: boolean;
  children: ReactNode;
}

export const Button = forwardRef<HTMLButtonElement, ButtonProps>(
  ({ variant = 'primary', size = 'md', fullWidth = false, children, className, ...props }, ref) => {
    return (
      <button
        ref={ref}
        className={cx(
          button({
            intent: variant,
            size,
            width: fullWidth ? 'full' : 'auto',
          }),
          className,
        )}
        {...props}
      >
        {children}
      </button>
    );
  },
);

Button.displayName = 'Button';
```

```ts
// src/components/Button/index.ts
export { Button } from './Button';
export type { ButtonProps } from './Button';
```

## Theming support

### Dark theme

```ts
// src/tokens/themes.ts
import { tokens } from 'typestyles';

export const darkTheme = tokens.createTheme('dark', {
  base: {
    'semantic-color': {
      primary: '#60a5fa',
      primaryHover: '#3b82f6',
      text: '#f9fafb',
      textMuted: '#9ca3af',
      background: '#111827',
      surface: '#1f2937',
      surfaceRaised: '#374151',
      border: '#4b5563',
    },
  },
});

export const highContrastTheme = tokens.createTheme('high-contrast', {
  base: {
    'semantic-color': {
      text: '#000000',
      background: '#ffffff',
      primary: '#0000ff',
      border: '#000000',
    },
  },
});
```

### Theme provider

```tsx
// src/components/ThemeProvider/ThemeProvider.tsx
import { createContext, useContext, useState, type ReactNode } from 'react';
import { darkTheme } from '../../tokens/themes';

interface ThemeContextValue {
  theme: 'light' | 'dark';
  setTheme: (theme: 'light' | 'dark') => void;
}

const ThemeContext = createContext<ThemeContextValue>({
  theme: 'light',
  setTheme: () => {},
});

export function useTheme() {
  return useContext(ThemeContext);
}

interface ThemeProviderProps {
  children: ReactNode;
  defaultTheme?: 'light' | 'dark';
}

export function ThemeProvider({ children, defaultTheme = 'light' }: ThemeProviderProps) {
  const [theme, setTheme] = useState(defaultTheme);

  return (
    <ThemeContext.Provider value={{ theme, setTheme }}>
      <div className={theme === 'dark' ? darkTheme.className : ''}>{children}</div>
    </ThemeContext.Provider>
  );
}
```

## Build configuration

